args.sqlite_command:
UPDATE J09D_temp SET ENTSCHEIDUNG = 'EVU'
WHERE CITY1 IN ('Wiblingwerde', 'Breckerfeld')
   OR CITY2 IN ('Wiblingwerde', 'Breckerfeld');

UPDATE J09D_joined
SET ENTSCHEIDUNG = 'MANDATORY_READING'
WHERE EQUNR IN (
    SELECT EQUNR FROM eabl_2023_2024
    WHERE MS_2023 > 0 AND MS_2024 > 0
);

UPDATE J09D_joined
SET ENTSCHEIDUNG = 'DIRECT_MAIL'
WHERE EQUNR IN (
    SELECT EQUNR FROM eabl_2023_2024
    WHERE AK_2023 > 0 AND AK_2024 > 0
);

